}

type AnthropicStreamBlockState = AnthropicTextBlockState | AnthropicToolUseBlockState;

export interface ProviderConfig {
  api_key?: string;
  api_key_env?: string;
  base_url: string;
  protocol?: "anthropic" | "openai" | "auto";
  version?: string;
  auth_header?: string;
  auth_prefix?: string;
  version_header?: string;
  headers?: Record<string, string>;
}

export interface RunModelInferenceArgs {
  model: string;
  max_tokens: number;
  messages: Message[];
  provider: ProviderConfig;
  systemPrompt: string;
  tools: ApiTool[];
  onTextDelta?: (text: string) => Promise<void> | void;
  onPartial?: (event: unknown) => Promise<void> | void;
  signal?: AbortSignal;
}

function detectProviderProtocol(baseUrl: string, configuredProtocol?: ProviderConfig["protocol"]): "anthropic" | "openai" {
  if (configuredProtocol && configuredProtocol !== "auto") {
    return configuredProtocol;
  }

  return baseUrl.includes("/chat/completions") ? "openai" : "anthropic";
}

function buildProviderHeaders(
  config: ProviderConfig,
  protocol: "anthropic" | "openai",
  apiKey: string,
): Record<string, string> {
  const authHeader = config.auth_header || (protocol === "openai" ? "Authorization" : "x-api-key");
  const authPrefix = config.auth_prefix ?? (protocol === "openai" ? "Bearer " : "");
  const versionHeader = config.version_header ?? (protocol === "anthropic" ? "anthropic-version" : undefined);

  const headers: Record<string, string> = {
    "content-type": "application/json",
    ...(config.headers ?? {}),
    [authHeader]: `${authPrefix}${apiKey}`,
  };

  if (config.version && versionHeader) {
    headers[versionHeader] = config.version;
  }

  return headers;
}

function normalizeOpenAIMessageContent(content: unknown): string {
  if (typeof content === "string") {
    return content;
  }

  if (!Array.isArray(content)) {
    return "";
  }

  return content
    .flatMap((part) => {
      if (!part || typeof part !== "object") {
        return [];
      }

      const item = part as { text?: unknown; type?: unknown };
      if (item.type === "text" && typeof item.text === "string") {
        return [item.text];
      }

      return [];
    })
    .join("\n");
}

function parseToolCallArguments(argumentsText: string, toolName: string): Record<string, unknown> {
  if (!argumentsText.trim()) {
    return {};
  }

  try {
    const parsed = JSON.parse(argumentsText) as unknown;
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
      throw new Error("Tool arguments must decode to an object");
    }

    return parsed as Record<string, unknown>;
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    throw new Error(`Invalid tool arguments for ${toolName}: ${message}`);
  }
}

function normalizeOpenAIResponse(payload: unknown): BetaMessage {
  const raw = payload as {
    choices?: Array<{
      finish_reason?: unknown;
      message?: {
        content?: unknown;
        tool_calls?: Array<{
          id?: unknown;
          function?: { arguments?: unknown; name?: unknown };
        }>;
      };
    }>;
    id?: unknown;
    model?: unknown;
    object?: unknown;
    usage?: { completion_tokens?: unknown; prompt_tokens?: unknown };
  };

  const choice = raw.choices?.[0];
  const message = choice?.message;
  if (!message) {
    throw new Error("Provider response missing choices[0].message");
  }

  const content: (TextBlock | ToolUseBlock)[] = [];
  const text = normalizeOpenAIMessageContent(message.content);
  if (text.trim()) {
    content.push({ type: "text", text });
  }

  for (const toolCall of message.tool_calls ?? []) {
    const name = typeof toolCall.function?.name === "string" ? toolCall.function.name : "";
    const id = typeof toolCall.id === "string" ? toolCall.id : "";
    if (!name || !id) {
      continue;
    }

    content.push({
      type: "tool_use",
      id,
      name,
      input: parseToolCallArguments(
        typeof toolCall.function?.arguments === "string" ? toolCall.function.arguments : "{}",
        name,
      ),
    });
  }

  return {
    id: typeof raw.id === "string" ? raw.id : "",
    type: typeof raw.object === "string" ? raw.object : "chat.completion",
    role: "assistant",
    content,
    stop_reason: typeof choice?.finish_reason === "string" ? choice.finish_reason : "stop",
    model: typeof raw.model === "string" ? raw.model : "",
    usage: {
      input_tokens: typeof raw.usage?.prompt_tokens === "number" ? raw.usage.prompt_tokens : 0,
      output_tokens: typeof raw.usage?.completion_tokens === "number" ? raw.usage.completion_tokens : 0,
    },
  };
}

function serializeMessagesForOpenAI(messages: Message[], systemPrompt: string): Array<Record<string, unknown>> {
  const serialized: Array<Record<string, unknown>> = [{ role: "system", content: systemPrompt }];

  for (const message of messages) {
    if (typeof message.content === "string") {
      serialized.push({ role: message.role, content: message.content });
      continue;
    }

    if (message.role === "assistant") {
      const text = message.content
        .filter((block): block is TextBlock => block.type === "text")
        .map((block) => block.text)
        .join("\n");
      const toolCalls = message.content
        .filter((block): block is ToolUseBlock => block.type === "tool_use")
        .map((block) => ({
          id: block.id,
          type: "function",
          function: {
            arguments: JSON.stringify(block.input),
            name: block.name,
          },
        }));

      if (text || toolCalls.length > 0) {
        serialized.push({
          role: "assistant",
          content: text || null,
          ...(toolCalls.length > 0 ? { tool_calls: toolCalls } : {}),
        });
      }

      continue;
    }

    const toolResults = message.content.filter((block) => block.type === "tool_result");
    if (toolResults.length === message.content.length) {
      for (const block of toolResults) {
        serialized.push({
          role: "tool",
          tool_call_id: block.tool_use_id,
          content:
            typeof block.content === "string"
              ? block.content
              : block.content
                  .map((item) => ("text" in item && item.type === "text" ? item.text : JSON.stringify(item)))
                  .join("\n"),
        });
      }
      continue;
    }

    serialized.push({
      role: message.role,
      content: message.content
        .filter((block): block is TextBlock => block.type === "text")
        .map((block) => block.text)
        .join("\n"),
    });
  }

  return serialized;
}

function serializeToolsForOpenAI(tools: ApiTool[]): Array<Record<string, unknown>> {
  return tools.map((tool) => ({
    type: "function",
    function: {
      description: tool.description,
      name: tool.name,
      parameters: tool.input_schema,
    },
  }));
}

async function processSSEEventBlock(
  rawEvent: string,
  onEvent: (event: SSEEvent) => Promise<void> | void,
): Promise<void> {
  let event = "message";
  const dataLines: string[] = [];

  for (const line of rawEvent.split("\n")) {
    if (!line || line.startsWith(":")) {
      continue;
    }

    const separatorIndex = line.indexOf(":");
    const field = separatorIndex === -1 ? line : line.slice(0, separatorIndex);
    const value = separatorIndex === -1 ? "" : line.slice(separatorIndex + 1).replace(/^ /, "");

    if (field === "event") {
      event = value || "message";
      continue;
    }

    if (field === "data") {
      dataLines.push(value);
    }
  }

  if (dataLines.length === 0) {
    return;
  }

  await onEvent({ event, data: dataLines.join("\n") });
}

async function readSSEEvents(
  body: ReadableStream<Uint8Array>,
  onEvent: (event: SSEEvent) => Promise<void> | void,
): Promise<void> {
  const reader = body.getReader();
  const decoder = new TextDecoder();
  let buffer = "";

  const processBuffer = async (flush = false): Promise<void> => {
    buffer = buffer.replace(/\r\n/g, "\n");

    for (;;) {
      const separatorIndex = buffer.indexOf("\n\n");
      if (separatorIndex === -1) {
        break;
      }

      const rawEvent = buffer.slice(0, separatorIndex);
      buffer = buffer.slice(separatorIndex + 2);
      await processSSEEventBlock(rawEvent, onEvent);
    }

    if (flush && buffer.trim()) {
      await processSSEEventBlock(buffer, onEvent);
      buffer = "";
    }
  };

  try {
    for (;;) {
      const { done, value } = await reader.read();
      if (done) {
        buffer += decoder.decode();
        await processBuffer(true);
        return;
      }

      buffer += decoder.decode(value, { stream: true });
      await processBuffer(false);
    }
  } finally {
    reader.releaseLock();
  }
}

async function parseOpenAIStreamResponse(
  response: Response,
  onTextDelta?: (text: string) => Promise<void> | void,
  onPartial?: (event: unknown) => Promise<void> | void,
): Promise<BetaMessage> {
  if (!response.body) {
    throw new Error("Streaming response missing body");
  }

  const state: OpenAIStreamAccumulator = {
    id: "",
    model: "",
    stop_reason: "stop",
    text: "",
    toolCalls: [],
    usage: {
      input_tokens: 0,
      output_tokens: 0,
    },
  };

  await readSSEEvents(response.body, async ({ data }) => {
    if (data === "[DONE]") {
      return;
    }

    const payload = JSON.parse(data) as {
      choices?: Array<{
        delta?: {
          content?: unknown;
          tool_calls?: Array<{
            function?: { arguments?: unknown; name?: unknown };
            id?: unknown;
            index?: unknown;
          }>;
        };
        finish_reason?: unknown;
      }>;
      id?: unknown;
      model?: unknown;
      usage?: { completion_tokens?: unknown; prompt_tokens?: unknown };
    };

    await onPartial?.(payload);

    if (typeof payload.id === "string" && !state.id) {
      state.id = payload.id;
    }

    if (typeof payload.model === "string" && !state.model) {
      state.model = payload.model;
    }

    if (typeof payload.usage?.prompt_tokens === "number") {
      state.usage.input_tokens = payload.usage.prompt_tokens;
    }

    if (typeof payload.usage?.completion_tokens === "number") {
      state.usage.output_tokens = payload.usage.completion_tokens;
    }

    const choice = payload.choices?.[0];
    if (!choice) {
      return;
    }

    if (typeof choice.finish_reason === "string") {
      state.stop_reason = choice.finish_reason;
    }

    const deltaText = normalizeOpenAIMessageContent(choice.delta?.content);
    if (deltaText) {
      state.text += deltaText;
      await onTextDelta?.(deltaText);
    }

    for (const toolCall of choice.delta?.tool_calls ?? []) {
      const index = typeof toolCall.index === "number" ? toolCall.index : -1;
      if (index < 0) {
        continue;
      }

      const current = state.toolCalls[index] ?? {
        id: "",
        name: "",
        argumentsText: "",
      };

      if (typeof toolCall.id === "string" && !current.id) {
        current.id = toolCall.id;
      }

      if (typeof toolCall.function?.name === "string") {
        current.name += toolCall.function.name;
      }

      if (typeof toolCall.function?.arguments === "string") {
        current.argumentsText += toolCall.function.arguments;
      }

      state.toolCalls[index] = current;
    }
  });

  const content: (TextBlock | ToolUseBlock)[] = [];
  if (state.text.trim()) {
    content.push({ type: "text", text: state.text });
  }

  for (const toolCall of state.toolCalls) {
    if (!toolCall?.id || !toolCall.name) {
      continue;
    }

    content.push({
      type: "tool_use",
      id: toolCall.id,
      name: toolCall.name,
      input: parseToolCallArguments(toolCall.argumentsText || "{}", toolCall.name),
    });
  }

  return {
    id: state.id,
    type: "chat.completion.chunk",
    role: "assistant",
    content,
    stop_reason: state.stop_reason,
    model: state.model,
    usage: state.usage,
  };
}

async function parseAnthropicStreamResponse(
  response: Response,
  onTextDelta?: (text: string) => Promise<void> | void,
  onPartial?: (event: unknown) => Promise<void> | void,
): Promise<BetaMessage> {
  if (!response.body) {
    throw new Error("Streaming response missing body");
  }

  let id = "";
  let model = "";
  let stop_reason: string | null = "end_turn";
  const usage: Usage = {
    input_tokens: 0,
    output_tokens: 0,
  };
  const blocks: AnthropicStreamBlockState[] = [];

  await readSSEEvents(response.body, async ({ event, data }) => {
    const payload = JSON.parse(data) as {
      content_block?: {
        id?: unknown;
        input?: unknown;
        name?: unknown;
        text?: unknown;
        type?: unknown;
      };
      delta?: {
        partial_json?: unknown;
        stop_reason?: unknown;
        text?: unknown;
        type?: unknown;
      };
      index?: unknown;
      message?: {
        id?: unknown;
        model?: unknown;
        usage?: { input_tokens?: unknown; output_tokens?: unknown };
      };
      usage?: { input_tokens?: unknown; output_tokens?: unknown };
    };

    await onPartial?.({ event, payload });

    if (event === "message_start") {
      if (typeof payload.message?.id === "string") {
        id = payload.message.id;
      }

      if (typeof payload.message?.model === "string") {
        model = payload.message.model;
      }

      if (typeof payload.message?.usage?.input_tokens === "number") {
        usage.input_tokens = payload.message.usage.input_tokens;
      }

      if (typeof payload.message?.usage?.output_tokens === "number") {
        usage.output_tokens = payload.message.usage.output_tokens;
      }

      return;
    }

    if (event === "content_block_start") {
      const index = typeof payload.index === "number" ? payload.index : blocks.length;
      const block = payload.content_block;

      if (block?.type === "text") {
        const text = typeof block.text === "string" ? block.text : "";
        blocks[index] = {
          type: "text",
          text,
        };

        if (text) {
          await onTextDelta?.(text);
        }
        return;
      }

      if (block?.type === "tool_use") {
        blocks[index] = {
          type: "tool_use",
          id: typeof block.id === "string" ? block.id : "",
          name: typeof block.name === "string" ? block.name : "",
          inputText:
            block.input && typeof block.input === "object" && !Array.isArray(block.input)
              ? JSON.stringify(block.input)
              : "",
        };
      }

      return;
    }

    if (event === "content_block_delta") {
      const index = typeof payload.index === "number" ? payload.index : -1;
      const block = index >= 0 ? blocks[index] : undefined;
      if (!block) {
        return;
      }

      if (block.type === "text" && payload.delta?.type === "text_delta") {
        const text = typeof payload.delta.text === "string" ? payload.delta.text : "";
        block.text += text;
        await onTextDelta?.(text);
        return;
      }

      if (block.type === "tool_use" && payload.delta?.type === "input_json_delta") {
        const partialJson = typeof payload.delta.partial_json === "string" ? payload.delta.partial_json : "";
        block.inputText += partialJson;
      }

      return;
    }

    if (event === "message_delta") {
      if (typeof payload.delta?.stop_reason === "string") {
        stop_reason = payload.delta.stop_reason;
      }

      if (typeof payload.usage?.input_tokens === "number") {
        usage.input_tokens = payload.usage.input_tokens;
      }

      if (typeof payload.usage?.output_tokens === "number") {
        usage.output_tokens = payload.usage.output_tokens;
      }
    }
  });

  const content: (TextBlock | ToolUseBlock)[] = [];
  for (const block of blocks) {
    if (!block) {
      continue;
    }

    if (block.type === "text") {
      if (block.text.trim()) {
        content.push({ type: "text", text: block.text });
      }
      continue;
    }

    if (!block.id || !block.name) {
      continue;
    }

    content.push({
      type: "tool_use",
      id: block.id,
      name: block.name,
      input: parseToolCallArguments(block.inputText || "{}", block.name),
    });
  }

  return {
    id,
    type: "message",
    role: "assistant",
    content,
    stop_reason,
    model,
    usage,
  };
}

export async function runModelInference(args: RunModelInferenceArgs): Promise<BetaMessage> {
  const apiKey = args.provider.api_key ?? (args.provider.api_key_env ? process.env[args.provider.api_key_env] : undefined);
  if (!apiKey) {
    const source = args.provider.api_key_env || "provider.api_key";
    throw new Error(`${source} environment variable is not set`);
  }

  const protocol = detectProviderProtocol(args.provider.base_url, args.provider.protocol);
  const headers = buildProviderHeaders(args.provider, protocol, apiKey);
  const streamEnabled = Boolean(args.onTextDelta || args.onPartial);

  const body =
    protocol === "openai"
      ? {
          model: args.model,
          max_tokens: args.max_tokens,
          messages: serializeMessagesForOpenAI(args.messages, args.systemPrompt),
          ...(streamEnabled ? { stream: true } : {}),
          ...(args.tools.length > 0 ? { tools: serializeToolsForOpenAI(args.tools) } : {}),
        }
      : {
          model: args.model,
          max_tokens: args.max_tokens,
          system: args.systemPrompt,
          messages: args.messages,
          ...(streamEnabled ? { stream: true } : {}),
          ...(args.tools.length > 0 ? { tools: args.tools } : {}),
        };

  const response = await fetch(args.provider.base_url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
    signal: args.signal,
  });

  if (!response.ok) {
    const errorBody = await response.text();
    throw new Error(`API error ${response.status}: ${errorBody}`);
  }

  const contentType = response.headers.get("content-type") ?? "";
  if (streamEnabled && contentType.includes("text/event-stream")) {
    return protocol === "openai"
      ? parseOpenAIStreamResponse(response, args.onTextDelta, args.onPartial)
      : parseAnthropicStreamResponse(response, args.onTextDelta, args.onPartial);
  }

  const responseBody = (await response.json()) as unknown;
  return protocol === "openai" ? normalizeOpenAIResponse(responseBody) : (responseBody as BetaMessage);
}

import { readFile, readdir, stat } from "fs/promises";
import * as path from "path";

import type { AgentDefinition, HookCallbackMatcher, McpServerConfig, Options, SdkPluginConfig } from "./types.ts";

export interface LoadedToolConfig {
  name: string;
  enabled: boolean;
  description: string;
  input_schema: Record<string, unknown>;
  source?: string;
  sourcePath?: string;
  timeout_ms?: number;
}

export interface SkillSummary {
  name: string;
  description: string;
  path: string;
  content: string;
}

export interface SlashCommandSummary {
  name: string;
  description: string;
  path: string;
  prompt: string;
}

export interface PluginSummary {
  name: string;
  path: string;
}

export interface AgentFileDefinition extends AgentDefinition {
  name: string;
  path: string;
}

export interface LoadedProjectConfig {
  name: string;
  model: string;
  max_tokens: number;
  system_prompt: string;
  provider: NonNullable<Options["provider"]>;
}

export interface LoadedProjectRuntime {
  config: LoadedProjectConfig;
  tools: LoadedToolConfig[];
  skills: SkillSummary[];
  slashCommands: SlashCommandSummary[];
  plugins: PluginSummary[];
  agents: Record<string, AgentDefinition>;
  mcpServers: Record<string, McpServerConfig>;
  hooks: Partial<Record<string, HookCallbackMatcher[]>>;
}

function stripQuotes(value: string): string {
  return value.trim().replace(/^['"]|['"]$/g, "");
}

function parseFrontmatter(markdown: string): Record<string, string> {
  const match = markdown.match(/^---\r?\n([\s\S]*?)\r?\n---/);
  if (!match) {
    return {};
  }

  const result: Record<string, string> = {};
  const frontmatter = match[1] ?? "";
  for (const line of frontmatter.split(/\r?\n/)) {
    const keyValue = line.match(/^([A-Za-z0-9_-]+):\s*(.+)$/);
    if (!keyValue) {
      continue;
    }

    const key = keyValue[1];
    const value = keyValue[2];
    if (!key || !value) {
      continue;
    }

    result[key] = stripQuotes(value);
  }

  return result;
}

async function readJSONFile<T>(filePath: string): Promise<T | null> {
  try {
    const raw = await readFile(filePath, "utf-8");
    return JSON.parse(raw) as T;
  } catch {
    return null;
  }
}

async function discoverSkills(skillsDir: string, workspaceDir: string): Promise<SkillSummary[]> {
  const dirStat = await stat(skillsDir).catch(() => null);
  if (!dirStat?.isDirectory()) {
    return [];
  }

  const entries = await readdir(skillsDir, { withFileTypes: true });
  const skills: SkillSummary[] = [];

  for (const entry of entries.sort((a, b) => a.name.localeCompare(b.name))) {
    if (!entry.isDirectory()) {
      continue;
    }

    const skillFile = path.join(skillsDir, entry.name, "SKILL.md");
    const fileStat = await stat(skillFile).catch(() => null);
    if (!fileStat?.isFile()) {
      continue;
    }

    const content = await readFile(skillFile, "utf-8");
    const frontmatter = parseFrontmatter(content);
    skills.push({
      name: frontmatter.name || entry.name,
      description: frontmatter.description || "No description provided.",
      path: path.relative(workspaceDir, skillFile) || "SKILL.md",
      content,
    });
  }

  return skills;
}

async function discoverSlashCommands(commandsDir: string, workspaceDir: string): Promise<SlashCommandSummary[]> {
  const dirStat = await stat(commandsDir).catch(() => null);
  if (!dirStat?.isDirectory()) {
    return [];
  }

  const entries = await readdir(commandsDir, { withFileTypes: true });
  const commands: SlashCommandSummary[] = [];

  for (const entry of entries.sort((a, b) => a.name.localeCompare(b.name))) {
    if (!entry.isFile() || !entry.name.endsWith(".md")) {
      continue;
    }

    const commandPath = path.join(commandsDir, entry.name);
    const prompt = await readFile(commandPath, "utf-8");
    const frontmatter = parseFrontmatter(prompt);
    const name = entry.name.replace(/\.md$/i, "");

    commands.push({
      name,
      description: frontmatter.description || `Slash command ${name}`,
      path: path.relative(workspaceDir, commandPath),
      prompt,
    });
  }

  return commands;
}

async function discoverAgents(agentsDir: string, workspaceDir: string): Promise<AgentFileDefinition[]> {
  const dirStat = await stat(agentsDir).catch(() => null);
  if (!dirStat?.isDirectory()) {
    return [];
  }

  const entries = await readdir(agentsDir, { withFileTypes: true });
  const agents: AgentFileDefinition[] = [];

  for (const entry of entries.sort((a, b) => a.name.localeCompare(b.name))) {
    if (!entry.isFile() || !entry.name.endsWith(".md")) {
      continue;
    }

    const filePath = path.join(agentsDir, entry.name);
    const raw = await readFile(filePath, "utf-8");
    const frontmatter = parseFrontmatter(raw);
    const prompt = raw.replace(/^---\r?\n[\s\S]*?\r?\n---\r?\n?/, "").trim();
    const name = frontmatter.name || entry.name.replace(/\.md$/i, "");

    agents.push({
      name,
      path: path.relative(workspaceDir, filePath),
      description: frontmatter.description || `Subagent ${name}`,
      prompt,
      maxTurns: frontmatter.max_turns ? Number(frontmatter.max_turns) : undefined,
      model: frontmatter.model,
      tools: frontmatter.tools ? frontmatter.tools.split(",").map((item) => stripQuotes(item)) : undefined,
      skills: frontmatter.skills ? frontmatter.skills.split(",").map((item) => stripQuotes(item)) : undefined,
    });
  }

  return agents;
}

async function loadTools(toolsDir: string): Promise<LoadedToolConfig[]> {
  const toolsFile = path.join(toolsDir, "tools.json");
  const config = await readJSONFile<{ tools?: Array<Record<string, unknown>> }>(toolsFile);
  if (!config?.tools) {
    return [];
  }

  return config.tools.map((tool) => {
    const source = typeof tool.source === "string" ? tool.source : undefined;
    return {
      name: String(tool.name ?? ""),
      enabled: tool.enabled !== false,
      description: String(tool.description ?? ""),
      input_schema:
        tool.input_schema && typeof tool.input_schema === "object" && !Array.isArray(tool.input_schema)
          ? (tool.input_schema as Record<string, unknown>)
          : {},
      source,
      sourcePath: source ? path.resolve(toolsDir, source) : undefined,
      timeout_ms: typeof tool.timeout_ms === "number" ? tool.timeout_ms : 30_000,
    };
  });
}

async function loadPlugins(baseDir: string, pluginConfigs: SdkPluginConfig[] = []): Promise<PluginSummary[]> {
  const fromProjectDir = path.join(baseDir, "plugins");
  const discovered: PluginSummary[] = [];

  const projectDirStat = await stat(fromProjectDir).catch(() => null);
  if (projectDirStat?.isDirectory()) {
    const entries = await readdir(fromProjectDir, { withFileTypes: true });
    for (const entry of entries) {
      if (!entry.isDirectory()) {
        continue;
      }

      discovered.push({
        name: entry.name,
        path: path.join(fromProjectDir, entry.name),
      });
    }
  }

  for (const plugin of pluginConfigs) {
    discovered.push({
      name: path.basename(plugin.path),
      path: path.resolve(baseDir, plugin.path),
    });
  }

  const deduped = new Map<string, PluginSummary>();
  for (const plugin of discovered) {
    deduped.set(plugin.path, plugin);
  }

  return [...deduped.values()];
}

function defaultProjectConfig(): LoadedProjectConfig {
  return {
    name: "Pinocchio",
    model: "",
    max_tokens: 1024,
    system_prompt: "",
    provider: {
      api_key_env: "ANTHROPIC_API_KEY",
      base_url: "https://api.anthropic.com/v1/messages",
      protocol: "auto",
      version: "2023-06-01",
    },
  };
}

export async function loadProjectRuntime(
  cwd: string,
  pluginConfigs: SdkPluginConfig[] = [],
): Promise<LoadedProjectRuntime> {
  const projectDir = path.join(cwd, ".pinocchio");
  const configRaw = await readJSONFile<Record<string, unknown>>(path.join(projectDir, "config.json"));
  const baseConfig = defaultProjectConfig();

  const config: LoadedProjectConfig = {
    name: typeof configRaw?.name === "string" ? configRaw.name : baseConfig.name,
    model: typeof configRaw?.model === "string" ? configRaw.model : baseConfig.model,
    max_tokens: typeof configRaw?.max_tokens === "number" ? configRaw.max_tokens : baseConfig.max_tokens,
    system_prompt:
      typeof configRaw?.system_prompt === "string" ? configRaw.system_prompt : baseConfig.system_prompt,
    provider: {
      ...baseConfig.provider,
      ...((configRaw?.provider as Record<string, unknown> | undefined) ?? {}),
    } as LoadedProjectConfig["provider"],
  };

  const tools = await loadTools(path.join(projectDir, "tools"));
  const skills = await discoverSkills(path.join(projectDir, "skills"), cwd);
  const slashCommands = await discoverSlashCommands(path.join(projectDir, "commands"), cwd);
  const agentFiles = await discoverAgents(path.join(projectDir, "agents"), cwd);
  const plugins = await loadPlugins(projectDir, pluginConfigs);
  const mcpServers =
    (await readJSONFile<Record<string, McpServerConfig>>(path.join(projectDir, "mcp.json"))) ?? {};

  const agents: Record<string, AgentDefinition> = {};
  for (const agent of agentFiles) {
    agents[agent.name] = {
      description: agent.description,
      prompt: agent.prompt,
      tools: agent.tools,
      skills: agent.skills,
      maxTurns: agent.maxTurns,
      model: agent.model,
    };
  }

  for (const plugin of plugins) {
    const pluginConfig = await readJSONFile<{ name?: string }>(path.join(plugin.path, ".pinocchio-plugin", "plugin.json"));
    if (pluginConfig?.name) {
      plugin.name = pluginConfig.name;
    }

    const pluginTools = await loadTools(path.join(plugin.path, "tools"));
    tools.push(...pluginTools);

    const pluginSkills = await discoverSkills(path.join(plugin.path, "skills"), cwd);
    skills.push(...pluginSkills);

    const pluginCommands = await discoverSlashCommands(path.join(plugin.path, "commands"), cwd);
    slashCommands.push(...pluginCommands);

    const pluginAgents = await discoverAgents(path.join(plugin.path, "agents"), cwd);
    for (const agent of pluginAgents) {
      agents[agent.name] = {
        description: agent.description,
        prompt: agent.prompt,
        tools: agent.tools,
        skills: agent.skills,
        maxTurns: agent.maxTurns,
        model: agent.model,
      };
    }

    const pluginMcp = await readJSONFile<Record<string, McpServerConfig>>(path.join(plugin.path, "mcp.json"));
    if (pluginMcp) {
      Object.assign(mcpServers, pluginMcp);
    }
  }

  return {
    config,
    tools,
    skills,
    slashCommands,
    plugins,
    agents,
    mcpServers,
    hooks: {},
  };
}

import { appendFile, mkdir, readFile, readdir, rm, stat, unlink, writeFile } from "fs/promises";
import * as path from "path";

import type { RewindFilesResult, SDKMessage, SessionInfo, SessionMessageRecord } from "./types.ts";

function sessionsDir(cwd: string): string {
  return path.join(cwd, ".pinocchio", "sessions");
}

function checkpointsDir(cwd: string, sessionId: string): string {
  return path.join(cwd, ".pinocchio", "checkpoints", sessionId);
}

function infoPath(cwd: string, sessionId: string): string {
  return path.join(sessionsDir(cwd), `${sessionId}.info.json`);
}

function transcriptPath(cwd: string, sessionId: string): string {
  return path.join(sessionsDir(cwd), `${sessionId}.jsonl`);
}

async function ensureDir(dirPath: string): Promise<void> {
  await mkdir(dirPath, { recursive: true });
}

export async function appendSessionMessage(cwd: string, sessionId: string, record: SessionMessageRecord): Promise<void> {
  await ensureDir(sessionsDir(cwd));
  await appendFile(transcriptPath(cwd, sessionId), `${JSON.stringify(record)}\n`, "utf-8");
}

export async function readSessionMessages(cwd: string, sessionId: string): Promise<SessionMessageRecord[]> {
  const filePath = transcriptPath(cwd, sessionId);
  const raw = await readFile(filePath, "utf-8").catch(() => "");
  return raw
    .split(/\r?\n/)
    .filter(Boolean)
    .map((line) => JSON.parse(line) as SessionMessageRecord);
}

export async function writeSessionInfo(cwd: string, info: SessionInfo): Promise<void> {
  await ensureDir(sessionsDir(cwd));
  await writeFile(infoPath(cwd, info.sessionId), JSON.stringify(info, null, 2), "utf-8");
}

export async function readSessionInfo(cwd: string, sessionId: string): Promise<SessionInfo | null> {
  try {
    const raw = await readFile(infoPath(cwd, sessionId), "utf-8");
    return JSON.parse(raw) as SessionInfo;
  } catch {
    return null;
  }
}

export async function listStoredSessions(cwd: string): Promise<SessionInfo[]> {
  const dir = sessionsDir(cwd);
  const dirStat = await stat(dir).catch(() => null);
  if (!dirStat?.isDirectory()) {
    return [];
  }

  const entries = await readdir(dir, { withFileTypes: true });
  const infos: SessionInfo[] = [];
  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.endsWith(".info.json")) {
      continue;
    }

    const info = await readSessionInfo(cwd, entry.name.replace(/\.info\.json$/, ""));
    if (info) {
      infos.push(info);
    }
  }

  return infos.sort((a, b) => (b.updatedAt ?? 0) - (a.updatedAt ?? 0));
}

export async function renameStoredSession(cwd: string, sessionId: string, title: string): Promise<void> {
  const info = await readSessionInfo(cwd, sessionId);
  if (!info) {
    throw new Error(`Unknown session: ${sessionId}`);
  }

  info.title = title;
  info.updatedAt = Date.now();
  await writeSessionInfo(cwd, info);
}

export async function tagStoredSession(cwd: string, sessionId: string, tag: string): Promise<void> {
  const info = await readSessionInfo(cwd, sessionId);
  if (!info) {
    throw new Error(`Unknown session: ${sessionId}`);
  }

  info.tag = tag;
  info.updatedAt = Date.now();
  await writeSessionInfo(cwd, info);
}

export async function recordCheckpoint(
  cwd: string,
  sessionId: string,
  filePath: string,
  beforeContent: string | null,
): Promise<void> {
  const dir = checkpointsDir(cwd, sessionId);
  await ensureDir(dir);
  const timestamp = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  await writeFile(
    path.join(dir, `${timestamp}.json`),
    JSON.stringify(
      {
        filePath,
        beforeContent,
      },
      null,
      2,
    ),
    "utf-8",
  );
}

export async function rewindSessionFiles(cwd: string, sessionId: string): Promise<RewindFilesResult> {
  const dir = checkpointsDir(cwd, sessionId);
  const dirStat = await stat(dir).catch(() => null);
  if (!dirStat?.isDirectory()) {
    return {
      canRewind: false,
      error: "No checkpoints recorded for this session.",
    };
  }

  const entries = (await readdir(dir)).filter((entry) => entry.endsWith(".json")).sort().reverse();
  if (entries.length === 0) {
    return {
      canRewind: false,
      error: "No checkpoints recorded for this session.",
    };
  }

  const seen = new Set<string>();
  let insertions = 0;
  let deletions = 0;

  for (const entry of entries) {
    const raw = await readFile(path.join(dir, entry), "utf-8");
    const checkpoint = JSON.parse(raw) as { beforeContent: string | null; filePath: string };
    if (seen.has(checkpoint.filePath)) {
      continue;
    }

    seen.add(checkpoint.filePath);
    const current = await readFile(checkpoint.filePath, "utf-8").catch(() => "");
    insertions += Math.max(0, (checkpoint.beforeContent ?? "").length - current.length);
    deletions += Math.max(0, current.length - (checkpoint.beforeContent ?? "").length);

    if (checkpoint.beforeContent === null) {
      await unlink(checkpoint.filePath).catch(() => undefined);
    } else {
      await ensureDir(path.dirname(checkpoint.filePath));
      await writeFile(checkpoint.filePath, checkpoint.beforeContent, "utf-8");
    }
  }

  await rm(dir, { recursive: true, force: true });

  return {
    canRewind: true,
    filesChanged: [...seen],
    insertions,
    deletions,
  };
}

export async function upsertSessionInfo(
  cwd: string,
  sessionId: string,
  data: Partial<SessionInfo> & Pick<SessionInfo, "cwd">,
): Promise<SessionInfo> {
  const current = (await readSessionInfo(cwd, sessionId)) ?? {
    sessionId,
    cwd: data.cwd,
    createdAt: Date.now(),
    updatedAt: Date.now(),
    messageCount: 0,
  };

  const next: SessionInfo = {
    ...current,
    ...data,
    sessionId,
    updatedAt: Date.now(),
  };

  await writeSessionInfo(cwd, next);
  return next;
}

export function getFirstPrompt(messages: SDKMessage[]): string | undefined {
  return messages.find((message): message is Extract<SDKMessage, { type: "user" }> => message.type === "user")?.message
    .content;
}

